import json, pathlib
ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

EXODUS_CHRIST = {
  "19": {
    "1": "<p>The arrival at Sinai on the third month is the structural hinge of Exodus: everything before this is the journey from Egypt; everything after is the covenant at Sinai. Christ is the new covenant mediator (Heb 9:15; 12:24) toward whom this whole movement aimed &mdash; Israel was brought to the mountain so YHWH could dwell with them; Christ is the one through whom YHWH dwells in his people permanently (John 14:23; 1 Cor 3:16).</p>",
    "2": "<p>Israel camped in the wilderness opposite the mountain. The meeting at the mountain &mdash; YHWH descends, Israel assembles below &mdash; is the type of the Incarnation-encounter: YHWH descends in human flesh to the level of his people, and they are drawn to him (John 12:32). The gathering of the whole community reflects the eschatological gathering of all nations to the mountain of YHWH (Isa 2:2-3; Heb 12:22-24).</p>",
    "3": "<p>Moses went up to God; YHWH called to him from the mountain. The mediatorial ascent of Moses &mdash; going up into the divine presence on behalf of the people &mdash; is the type of Christ&apos;s ascension (Heb 9:24). Moses goes up to receive the covenant; Christ ascends to present his blood and secure the new covenant. Moses came down to the people; Christ sends the Spirit to his people (John 14:16-18; Acts 2).</p>",
    "4": "<p>&ldquo;I carried you on eagles&apos; wings and brought you to myself.&rdquo; YHWH&apos;s drawing of Israel to himself is the type of the Father&apos;s drawing of people to the Son: &ldquo;No one can come to me unless the Father who sent me draws him&rdquo; (John 6:44). The eagle-wings image (Deut 32:11; Ps 36:7; 91:4) of divine protective transport is the type of the Spirit who carries believers into union with Christ (Gal 5:25; Eph 2:5-6).</p>",
    "5": "<p>&ldquo;You will be my treasured possession (<em>segulah</em>) out of all the nations.&rdquo; The segulah-language is applied to the church in 1 Pet 2:9 (&ldquo;a people for his own possession&rdquo;) and Titus 2:14 (&ldquo;a people of his own possession, zealous for good works&rdquo;). Christ&apos;s death purchases for himself a people who are his treasured possession &mdash; the new Israel gathered from every nation (Rev 5:9-10).</p>",
    "6": "<p>&ldquo;You will be for me a kingdom of priests (<em>mamlekhet kohanim</em>) and a holy nation (<em>goy kadosh</em>).&rdquo; Applied to the church in 1 Pet 2:9 (&ldquo;a royal priesthood, a holy nation&rdquo;) and Rev 1:6; 5:10; 20:6 (&ldquo;a kingdom of priests to our God&rdquo;). Christ as both King and High Priest (Heb 7:1-3; Ps 110:4) is himself the Melchizedekian fulfillment of both titles, and through him his people share both vocations.</p>",
    "7": "<p>Moses summons the elders and sets before them all YHWH&apos;s words. The role of Moses as covenant-transmitter &mdash; YHWH speaks to Moses, Moses to the elders, the elders to the people &mdash; is the type of the prophetic-apostolic chain: Christ speaks to the apostles, who speak to the church. Heb 1:1-2: &ldquo;In these last days he has spoken to us by his Son.&rdquo;</p>",
    "8": "<p>&ldquo;All the people responded together: We will do everything YHWH has said.&rdquo; The people&apos;s covenant commitment &mdash; made in good faith but unrealized in practice (the golden calf follows in ch 32) &mdash; is the OT demonstration of the need for a new covenant (Jer 31:31-34). The inability to keep the Sinai covenant is the OT argument for Christ: Israel&apos;s repeated failure proves that human resolution cannot achieve covenant obedience; a new heart must be given (Ezek 36:26-27).</p>",
    "9": "<p>YHWH comes in a thick cloud so the people will hear him speaking with Moses. The cloud conceals YHWH from direct vision. The contrast with the Incarnation is sharp: in Christ, YHWH becomes visible, audible, and touchable &mdash; &ldquo;what we have heard, what we have seen with our eyes, what we have looked at and touched with our hands&rdquo; (1 John 1:1-3). Sinai&apos;s concealing cloud and the Incarnation&apos;s visible fullness form an instructive contrast in Hebrews (Heb 12:18-24).</p>",
    "10": "<p>Consecration before YHWH&apos;s appearance &mdash; washing clothes and preparing on the third day. The third-day timing is Christologically significant: YHWH descends on the third day; Christ is raised on the third day (1 Cor 15:4). The pattern of a three-day preparation before divine encounter on the third day runs from Exod 19 through the resurrection narrative. The washing-before-approach is the type of baptismal preparation (Heb 10:22; Titus 3:5).</p>",
    "11": "<p>&ldquo;On the third day YHWH will come down on Mount Sinai in the sight of all the people.&rdquo; The third-day descent of YHWH in fire and cloud is the most significant OT type of the resurrection-revelation: YHWH appears on the third day to the assembled community. Christ rises on the third day and appears to his community (1 Cor 15:5-8). Both events are the definitive public revelation of YHWH&apos;s power over death and covenant faithfulness.</p>",
    "12": "<p>The boundaries around the mountain &mdash; the people must not go up or touch it, on pain of death. Heb 12:18-19 cites these very boundaries as the terror of the old covenant: &ldquo;the blazing fire and darkness and gloom and a tempest&rdquo; from which the people shrank back. The contrast in Heb 12:22-24: &ldquo;But you have come to Mount Zion&rdquo; &mdash; through Christ&apos;s blood, the barriers are removed and bold approach is possible (Heb 10:19-22).</p>",
    "13": "<p>Even the animal that touches the mountain must die &mdash; stoned or shot with arrows. The death-consequence for unauthorized approach to divine holiness reflects the infinite distance between the holy God and sinful humanity. Christ is the one who crossed that boundary on our behalf &mdash; he bore the penalty of unauthorized approach (death) so that his people might have authorized, perpetual access (Eph 2:18; Heb 4:16).</p>",
    "14": "<p>Moses consecrates the people &mdash; they wash their clothes. The priestly act of preparation for divine encounter is performed by Moses as mediator. Christ himself is the one who washes and consecrates his people: &ldquo;Christ loved the church and gave himself up for her, that he might sanctify her, having cleansed her by the washing of water with the word&rdquo; (Eph 5:25-26). The external washing of clothes is the type of the internal cleansing of conscience (Heb 9:14).</p>",
    "15": "<p>The instruction to abstain from sexual relations before the third day &mdash; ritual purity before meeting YHWH. Paul applies bodily purity language to the church as the temple of the Spirit: &ldquo;Your body is a temple of the Holy Spirit&rdquo; (1 Cor 6:19-20). The preparatory abstinence for Sinai is the type of the ongoing holiness required to live in the immediate presence of YHWH through the Spirit (2 Cor 6:14-7:1).</p>",
    "16": "<p>Thunder, lightning, thick cloud, and very loud trumpet blast on the third day &mdash; the people trembled. Heb 12:19-21 names the trumpet and the voice as among the things that caused Israel to beg that no further word be spoken. The terror of Sinai communicates the infinite holiness of YHWH; the new covenant&apos;s access through Christ does not abolish that holiness but provides a mediator equal to its demands (Heb 7:26-27).</p>",
    "17": "<p>Moses led the people out of the camp to meet with God &mdash; they stood at the foot of the mountain. The corporate assembly before YHWH is the type of the eschatological assembly before the throne (Rev 7:9-12; 19:1-8). Moses leading the people to the meeting is the type of Christ leading his flock into the Father&apos;s presence (John 10:27-29; Heb 2:13: &ldquo;Here am I, and the children God has given me&rdquo;).</p>",
    "18": "<p>Mount Sinai covered in smoke because YHWH descended in fire &mdash; the smoke billowed up like smoke from a furnace. The Spirit descended at Pentecost as &ldquo;tongues of fire&rdquo; (Acts 2:3). The Sinai fire-theophany is the type of the Pentecost fire-theophany: both mark a covenant inauguration. At Sinai YHWH came in fire to give the law; at Pentecost the Spirit came in fire to write the law on hearts (Jer 31:33; 2 Cor 3:3-6).</p>",
    "19": "<p>The trumpet grew louder and louder; Moses spoke and God answered him. The loud trumpet at the covenant meeting is the type of the last trumpet (1 Cor 15:52; 1 Thess 4:16; Rev 11:15) &mdash; YHWH&apos;s voice like a trumpet announcing covenant assembly prefigures the eschatological trumpet that announces the final gathering and the completion of all covenant promises.</p>",
    "20": "<p>YHWH descends to the top of Sinai and calls Moses up. The ascent-of-the-mediator-into-divine-presence is the type of Christ&apos;s ascension (Eph 4:8-10, citing Ps 68:18: &ldquo;When he ascended on high, he led captives in his train&rdquo;). Moses goes up to receive the covenant; Christ ascends to present his blood and secure the eternal covenant (Heb 9:11-14). Moses descends to the people with the law; Christ sends the Spirit with new-covenant life.</p>",
    "21": "<p>YHWH warns that the people must not force their way through to see him, or many will perish. The prohibition on unauthorized approach is the negative context for Heb 10:19-22&apos;s invitation: &ldquo;therefore, brothers, since we have confidence to enter the holy places by the blood of Jesus.&rdquo; The barrier Sinai erected, Christ&apos;s blood removes &mdash; not by lowering YHWH&apos;s holiness but by providing the perfect High Priest who has met its demands.</p>",
    "22": "<p>Even the priests who approach YHWH must consecrate themselves or he will break out against them. Christ is the high priest whose holiness is intrinsic, not derived (Heb 7:26-27: &ldquo;holy, innocent, undefiled, separated from sinners&rdquo;). He needs no prior consecration because he is the source of all holiness. His self-consecration (John 17:19: &ldquo;I consecrate myself&rdquo;) enables the consecration of his people.</p>",
    "23": "<p>Moses&apos;s protest &mdash; the people cannot come up; YHWH warned us: &ldquo;set boundaries around the mountain and consecrate it.&rdquo; Moses intercedes on behalf of the people, clarifying the limits already established. The intercessory function of Moses before YHWH when the people&apos;s welfare is at stake is the type of Christ&apos;s perpetual intercession: &ldquo;he always lives to make intercession for them&rdquo; (Heb 7:25).</p>",
    "24": "<p>YHWH&apos;s graduated access: Moses and Aaron may come up; the priests and people must not break through. The structure of graduated access at Sinai (Moses &rarr; Aaron &rarr; priests &rarr; people &rarr; none) is the old covenant&apos;s access structure. Christ dismantles the gradient: he is the single point of access, and through him all believers have equal boldness before the Father (Eph 2:18: &ldquo;through him we both have access to the Father by one Spirit&rdquo;).</p>",
    "25": "<p>Moses goes down and tells the people. The mediator&apos;s movement: up into the divine presence, down to the human community, back up again. The repeated ascents and descents of Moses sketch the pattern fulfilled in Christ&apos;s incarnation-crucifixion-resurrection-ascension: the complete movement of the divine mediator through every level of the cosmos for the sake of his people (Eph 4:9-10).</p>"
  },
  "20": {
    "1": "<p>God spoke all these words &mdash; the Decalogue&apos;s divine origin is absolute. Jesus in the Sermon on the Mount claims equal authority with the Decalogue&apos;s Giver: &ldquo;You have heard it said... but I say to you&rdquo; (Matt 5:21-48). He does not cite Torah as an authority above himself but speaks as the one through whom Torah was originally given &mdash; the Word who was with God in the beginning (John 1:1-3).</p>",
    "2": "<p>&ldquo;I am YHWH your God who brought you out of Egypt, out of the house of slavery.&rdquo; The gospel-before-law prologue: the commands follow from the prior act of grace. The same structure governs the NT: Christ&apos;s redemption (the new Exodus, Luke 9:31) grounds all subsequent ethical demands. Romans 12:1 &mdash; &ldquo;therefore, in view of God&apos;s mercy&rdquo; &mdash; is the NT equivalent of this prologue: imperatives follow from indicatives.</p>",
    "3": "<p>&ldquo;You shall have no other gods beside me.&rdquo; Christ fulfills this commandment perfectly: he has no competing allegiance, no divided loyalty. He is the one who perfectly answers &ldquo;Yes&rdquo; to all of YHWH&apos;s demands (2 Cor 1:20). His active obedience &mdash; the perfect keeping of every commandment &mdash; is counted as righteousness for those who trust in him (Rom 5:19; 2 Cor 5:21).</p>",
    "4": "<p>&ldquo;You shall not make for yourself an idol in the form of anything.&rdquo; Christ is the one legitimate image (<em>eikon</em>) of the invisible God (Col 1:15; 2 Cor 4:4; Heb 1:3). The prohibition of human-made images is not overturned by the Incarnation but fulfilled by it: YHWH himself provides the image that human hands may not make. Jesus is the image the second commandment forbids humans from manufacturing and that YHWH himself gives.</p>",
    "5": "<p>&ldquo;I am a jealous God.&rdquo; YHWH&apos;s jealousy is covenantal-marital exclusivity &mdash; the same passion that drives the new covenant. Paul uses the same jealousy-language for Christ and the church: &ldquo;I am jealous for you with a godly jealousy. I promised you to one husband, to Christ, so that I might present you as a pure virgin to him&rdquo; (2 Cor 11:2). The jealous God who forbids idols is Christ who will not share his bride with rivals.</p>",
    "6": "<p>&ldquo;Showing faithful love (<em>chesed</em>) to thousands who love me and keep my commandments.&rdquo; The covenant loyalty YHWH displays to thousands is supremely enacted in Christ&apos;s death: &ldquo;God demonstrates his own love for us in this: while we were still sinners, Christ died for us&rdquo; (Rom 5:8). The chesed promised in the Decalogue is fulfilled in the cross.</p>",
    "7": "<p>&ldquo;You shall not misuse the name of YHWH your God.&rdquo; Jesus came in the Father&apos;s name (John 5:43; 10:25) and revealed the Father&apos;s name to his disciples (John 17:6, 26). He glorified the Father&apos;s name throughout his ministry (John 12:28; 17:1-4). The negative prohibition on misusing the name finds its positive fulfillment in Christ who hallowed it perfectly.</p>",
    "8": "<p>&ldquo;Remember the Sabbath day by keeping it holy.&rdquo; Jesus is &ldquo;Lord of the Sabbath&rdquo; (Matt 12:8; Mark 2:28; Luke 6:5) &mdash; the Sabbath was made for humanity, and he is its Lord and fulfillment. Matt 11:28-30 &mdash; &ldquo;come to me, all you who are weary and burdened, and I will give you rest&rdquo; &mdash; is Jesus&apos;s invitation to the Sabbath rest he embodies. Heb 4:9-11 teaches that the true Sabbath-rest is entered by faith in Christ&apos;s finished work.</p>",
    "9": "<p>Six days of labor &mdash; the work-week is affirmed as divine institution. Christ himself worked: &ldquo;My Father is always at his work to this very day, and I too am working&rdquo; (John 5:17). The six-day work structure is not abolished but fulfilled in the new creation&apos;s week, which begins with the Sabbath-day resurrection (Matt 28:1; John 20:1 &mdash; the first day of the new creation week).</p>",
    "10": "<p>The seventh day is a Sabbath to YHWH &mdash; no work for anyone in the household, including servants and animals. The inclusive Sabbath rest &mdash; extending to every member of the household including foreigners and animals &mdash; is the type of the eschatological rest that encompasses all creation (Rom 8:21) and all peoples (Rev 7:9-10). Christ&apos;s rest is inclusive: &ldquo;Come to me, all you who are weary&rdquo; (Matt 11:28) &mdash; no exclusions.</p>",
    "11": "<p>&ldquo;For in six days YHWH made the heavens and the earth... but he rested on the seventh day.&rdquo; Creation Sabbath grounds the weekly Sabbath. Christ&apos;s rest in the tomb on the seventh day (Luke 23:54-56; Mark 15:42-47) is the fulfillment of creation&apos;s Sabbath: the one through whom all things were made (John 1:3; Col 1:16) rests in death on the seventh day, completing the work of new creation. The first day (Sunday) begins the new creation week with resurrection.</p>",
    "12": "<p>&ldquo;Honor your father and your mother.&rdquo; Jesus honored his mother (John 19:26-27) and submitted to his earthly parents (Luke 2:51-52). He also set the fifth commandment in its proper order: &ldquo;Whoever loves father or mother more than me is not worthy of me&rdquo; (Matt 10:37) &mdash; fulfilling the commandment while locating the supreme loyalty it ultimately requires. In John 19:26-27, he fulfills the commandment&apos;s care-of-parents dimension from the cross itself.</p>",
    "13": "<p>&ldquo;You shall not murder.&rdquo; Jesus deepens this commandment to the heart level: anger and contempt are murder&apos;s root (Matt 5:21-22). He himself is the innocent one murdered by those who fulfilled the worst logic of this commandment&apos;s violation (Acts 2:23; 3:15). His death at human hands, combined with his forgiveness of those hands (&ldquo;Father, forgive them,&rdquo; Luke 23:34), is the commandment&apos;s ultimate exposure and the grace that transcends it.</p>",
    "14": "<p>&ldquo;You shall not commit adultery.&rdquo; Jesus deepens this to the level of desire (Matt 5:27-28). He is the faithful husband-figure (Mark 2:19-20; John 3:29) whose covenant fidelity is the standard for marital faithfulness. Eph 5:25-32 makes the husband-wife relationship a type of Christ-church: the absolute faithfulness of Christ to his bride defines what the commandment&apos;s fulfillment looks like.</p>",
    "15": "<p>&ldquo;You shall not steal.&rdquo; Christ &ldquo;emptied himself&rdquo; (Phil 2:6-7) and &ldquo;did not regard equality with God as something to be grasped.&rdquo; He fulfills the commandment by giving rather than taking &mdash; his entire ministry is the giving of what is his for the benefit of others. Eph 4:28 applies this positively: the one who was stealing must instead work to give to those in need, reflecting Christ&apos;s own economy of giving.</p>",
    "16": "<p>&ldquo;You shall not bear false testimony against your neighbor.&rdquo; Christ is &ldquo;the truth&rdquo; (John 14:6) &mdash; the one whose every word is true (John 8:45-46). At his trial he bore the false testimony of others (Mark 14:56-59) while himself bearing only true witness to the Father (Mark 14:62; John 18:37: &ldquo;for this I came into the world, to testify to the truth&rdquo;). The ninth commandment finds its positive fulfillment in the one who is Truth incarnate.</p>",
    "17": "<p>&ldquo;You shall not covet.&rdquo; Paul in Rom 7:7-8 identifies this as the commandment that most clearly revealed sin in him: &ldquo;I would not have known what coveting really was if the law had not said, &lsquo;Do not covet.&rsquo;&rdquo; Christ fulfills this by contentment and generosity: &ldquo;Godliness with contentment is great gain&rdquo; (1 Tim 6:6) traces to Christ&apos;s own disposition of trusting the Father&apos;s provision rather than grasping.</p>",
    "18": "<p>The people saw the thunder and lightning and the mountain in smoke &mdash; they trembled and stood at a distance. Heb 12:18-21 recounts this terror of Sinai in contrast to the boldness of the new covenant: the old covenant&apos;s encounter produced fear and distance; the new covenant&apos;s encounter through Christ&apos;s blood produces confidence and access (Heb 10:19; 4:16). The fear at Sinai is not wrong &mdash; it is accurate perception of divine holiness &mdash; but it is incomplete without the mediator who has satisfied that holiness.</p>",
    "19": "<p>&ldquo;Speak to us yourself and we will listen. But do not have God speak to us or we will die.&rdquo; The people&apos;s request for a human mediator &mdash; they cannot endure direct divine speech &mdash; is the OT expression of the Incarnation&apos;s necessity. The people need a human voice to mediate the divine word. Christ is the answer: the divine Word in human voice (John 1:14; Heb 1:1-2). The one through whom YHWH speaks in these last days is himself both fully divine and fully human &mdash; the mediator the people at Sinai needed.</p>",
    "20": "<p>&ldquo;God has come to test you, so that the fear of God will be with you, that you may not sin.&rdquo; The purpose of the terrifying theophany: holy fear preventing sin. Christ accomplishes this purpose by a different path &mdash; not terror but love (1 John 4:18-19: &ldquo;perfect love drives out fear... we love because he first loved us&rdquo;) while maintaining the ultimate seriousness of divine holiness: &ldquo;It is a fearful thing to fall into the hands of the living God&rdquo; (Heb 10:31).</p>",
    "21": "<p>Moses approached the thick darkness where God was &mdash; the people remained at a distance. Moses enters the cloud of divine presence; the people cannot. Christ is the new Moses who enters not into darkness but into the Father&apos;s light (1 Tim 6:16), and through his mediation draws his people into that same presence &mdash; not to the foot of the mountain but into the very holy of holies (Heb 10:19-22; John 14:3: &ldquo;I will come back and take you to be with me&rdquo;).</p>",
    "22": "<p>YHWH&apos;s first post-Decalogue instruction: &ldquo;You have seen that I have spoken to you from heaven &mdash; you shall not make gods of silver or gold.&rdquo; The prohibition against silver and gold gods follows immediately after the Decalogue. The Incarnation is YHWH&apos;s definitive self-revelation that replaces all human-made representations: &ldquo;The Son is the radiance of God&apos;s glory and the exact representation of his being&rdquo; (Heb 1:3).</p>",
    "23": "<p>&ldquo;Do not make alongside me gods of silver or gods of gold.&rdquo; The restatement of the second commandment applied to the worship context. Christ is the one alongside whom no other god stands &mdash; all things were created through him and for him (Col 1:16), and he is the image of the invisible God (Col 1:15). No silver or gold image captures what the Incarnation reveals; no human-made god competes with the one the Father sent.</p>",
    "24": "<p>The earthen altar &mdash; simplicity of approach before YHWH. The first altar instruction emphasizes accessibility over architecture: an earthen altar, anywhere YHWH causes his name to be remembered. The simplicity contrasts with the elaborate tabernacle and points forward to Christ&apos;s own statement: &ldquo;Where two or three gather in my name, there am I with them&rdquo; (Matt 18:20). The presence of YHWH among his people is not dependent on elaborate structure.</p>",
    "25": "<p>If the altar is of stone, it must be unhewn &mdash; the chisel desecrates it. The principle: YHWH&apos;s altar must not bear human marks of improvement. The same principle governs the new covenant: Christ is the cornerstone and foundation that no human hand shapes (Acts 4:11; 1 Pet 2:4-6). His sacrifice needs no human supplement or improvement; any addition desecrates rather than improves.</p>",
    "26": "<p>&ldquo;Do not go up to my altar by steps, so your nakedness will not be exposed.&rdquo; The altar must preserve human dignity before YHWH &mdash; no steps that would expose nakedness. The principle of covered approach is the type of the righteousness-covering that enables approach to God: Christ&apos;s righteousness covers the believer&apos;s shame (Gal 3:27; Rev 3:18), making approach to God possible without the exposure of unworthiness.</p>"
  },
  "21": {
    "1": "<p>The ordinances (<em>mishpatim</em>) &mdash; the case law of the Book of the Covenant (20:22-23:33) that applies the Decalogue&apos;s principles to specific situations. Jesus fulfills and deepens this legal tradition in the Sermon on the Mount (Matt 5:17-48) and in his summary of the law (Matt 22:37-40). He came not to abolish the law but to fulfill it &mdash; filling it with its deepest intent and bearing its full obligation on behalf of his people (Gal 3:13; Rom 8:3-4).</p>",
    "2": "<p>The Hebrew slave law &mdash; six years of service, freedom in the seventh. The sabbatical structure applied to human servitude. Christ announced fulfillment of this release-structure in Luke 4:18-19 (citing Isa 61:1): &ldquo;He has sent me to proclaim liberty to the captives.&rdquo; He is the one who brings the ultimate jubilee: release from slavery to sin and death (Rom 6:17-18; Gal 5:1: &ldquo;It is for freedom that Christ has set us free&rdquo;).</p>",
    "3": "<p>The slave who came single leaves single; the slave who came married leaves with his wife. The law protects the existing family unit when freedom comes. The principle of protecting family relationships in the act of liberation is the type of Christ&apos;s redemption, which does not dissolve but hallows existing covenant relationships (1 Cor 7:20-24).</p>",
    "4": "<p>If the master gave the slave a wife during service, the wife and children belong to the master at freedom. The complexity of this provision points to the legal framework designed to prevent exploitation: the slave cannot acquire a free-born household through the master&apos;s gift and then depart with it. The provision prioritizes clear legal status over sentiment &mdash; a principle governing the laws of property and persons throughout the Book of the Covenant.</p>",
    "5": "<p>The slave who loves his master and refuses freedom &mdash; &ldquo;I love my master and my wife and children and do not want to go free.&rdquo; Ps 40:6-8 applies this image to Christ: &ldquo;Ears you have opened for me&rdquo; (LXX: &ldquo;a body you have prepared for me&rdquo;) &mdash; cited in Heb 10:5-7 as Christ&apos;s words at the Incarnation: &ldquo;I have come to do your will, O God.&rdquo; Christ is the eternal servant-Son who voluntarily entered servitude for his master (the Father) and his household (his people), choosing bondage out of love.</p>",
    "6": "<p>&ldquo;His master must take him before the judges and bring him to the door or doorpost. There his master shall pierce his ear with an awl.&rdquo; The ear-piercing at the doorpost is the voluntary-servitude sign. Ps 40:6&apos;s &ldquo;ears you have opened (<em>karitha</em>, bored/dug)&rdquo; &mdash; applied in Heb 10:5-7 to Christ&apos;s incarnational commitment &mdash; is likely an allusion to this passage. The opened ear is the sign of the one who chose to remain in service out of love rather than claiming his rights.</p>",
    "7": "<p>The female slave sold by her father &mdash; she is not released on the same terms as a male slave. The law provides for her protection (vv. 7-11) rather than simply granting her the same release. The differentiated provision reflects the legal complexity of the ANE household; its direction is protective rather than subordinating. Christ&apos;s ministry showed particular care for women who were legally vulnerable (Luke 7:36-50; 8:2-3; John 4:1-26; 8:3-11).</p>",
    "8": "<p>If the master who selected her does not find her pleasing, he must allow her redemption &mdash; he cannot sell her to foreigners, having dealt unfaithfully with her. The prohibition on betrayal-sale protects the enslaved woman from being trafficked. The law&apos;s direction is consistently toward protecting the vulnerable from exploitation. Christ&apos;s own redemption of the church is called by the same term &mdash; <em>ga&apos;al</em>, redeem &mdash; YHWH who redeems those who have been dealt with unfaithfully by sin (Gal 3:13; Rev 5:9).</p>",
    "9": "<p>If the master selects her for his son, he must treat her as he would a daughter. The adoption-through-marriage principle: belonging to the son&apos;s household elevates the enslaved woman&apos;s status to daughter. This is the type of the believer&apos;s adoption through union with the Son: &ldquo;you received the Spirit of adoption as sons&rdquo; (Rom 8:15); belonging to Christ brings sonship/daughtership in the Father&apos;s household.</p>",
    "10": "<p>The master who marries another must not reduce the first woman&apos;s food, clothing, or marital rights. The protection of the first wife&apos;s rights preserves the covenant obligations of the first union. Christ as husband of the church is the faithful covenant-keeper who withholds nothing good from his bride (Eph 5:25-29: &ldquo;he who loves his wife loves himself&rdquo;).</p>",
    "11": "<p>If the master fails to provide these three things, the enslaved woman goes free without paying anything. Release without payment &mdash; freedom at no cost to the one released &mdash; is the structure of grace. Christ&apos;s redemption of his people costs them nothing: &ldquo;you were bought at a price&rdquo; (1 Cor 6:20), but the price was paid by him, not by those redeemed (Isa 52:3; 1 Pet 1:18-19).</p>",
    "12": "<p>Anyone who strikes and kills another must be put to death. The lex talionis principle applied to capital cases: life for life. Christ bore this death-penalty not for his own violence but for ours: &ldquo;he was pierced for our transgressions&rdquo; (Isa 53:5). The very law that condemns the murderer pronounces Christ&apos;s death &mdash; he who knew no sin was made sin for us (2 Cor 5:21), bearing the capital penalty of the law&apos;s violation.</p>",
    "13": "<p>Unintentional killing &mdash; a city of refuge is provided. &ldquo;God allowed it to happen&rdquo; &mdash; the distinction between intentional and unintentional reflects a theology of providence underlying the law. Christ is the ultimate city of refuge (Heb 6:18: &ldquo;we who have fled to take hold of the hope set before us&rdquo;) &mdash; the one to whom the guilty flee and find an asylum that not even the avenger of blood can penetrate.</p>",
    "14": "<p>Deliberate, scheming murder &mdash; even from YHWH&apos;s altar the killer is to be taken and executed. The altar provides no asylum for premeditated murder. This shows that the law&apos;s mercy (city of refuge) and justice (execution for premeditated murder) are both genuine. Christ bore the punishment of the deliberate, premeditated sinner while providing the refuge the law denied &mdash; not by reducing the penalty but by taking it himself (1 Pet 3:18).</p>",
    "15": "<p>Anyone who strikes their father or mother must be put to death. The severity of the penalty reflects the fifth commandment&apos;s centrality: parental authority is the foundation of all human social order. Jesus fulfilled this commandment while also setting it in its proper subordinate position to the first commandment (Matt 10:37; Luke 14:26). His honor of Joseph and Mary (Luke 2:51; John 19:26-27) models the commandment&apos;s fulfillment.</p>",
    "16": "<p>Kidnapping &mdash; stealing a person and selling them or being caught with them &mdash; is a capital offense. The image of God in every person makes their theft equal to murder in gravity. Christ&apos;s redemption of enslaved humanity (Gal 3:13; Col 1:13: &ldquo;he has rescued us from the dominion of darkness and brought us into the kingdom of the Son he loves&rdquo;) is the positive counterpart: he is the one who liberates the stolen and returns them to their rightful owner (the Father).</p>",
    "17": "<p>Anyone who curses their father or mother must be put to death. The severity parallels v15: the foundation of the covenant community in the household requires protection of parental authority from within as well as without. Jesus came not to abolish this commandment but to fulfill it &mdash; his own honor of his Father (John 8:49: &ldquo;I honor my Father&rdquo;) is the perfect fulfillment of the law he upholds.</p>",
    "18": "<p>The quarreling-and-injury law &mdash; one person hits another with a stone or fist; the injured person is bedridden but recovers. The law&apos;s graduated response: if recovery occurs, the striker pays for lost time and medical care but is not executed. Christ&apos;s own body was struck (Matt 26:67; 27:30; Isa 50:6: &ldquo;I offered my back to those who struck me&rdquo;) &mdash; he is the innocent one who received the injury the law was designed to adjudicate.</p>",
    "19": "<p>If the injured person recovers and walks around, the striker is not held responsible for death but must compensate for the convalescence. The law distinguishes between intention, outcome, and compensation: it does not treat all violence as equivalent but calibrates the response to the actual harm. The same principle governs divine justice: Christ&apos;s atonement is not a blanket payment but a precisely calibrated satisfaction of every specific debt (Rom 3:25-26: &ldquo;he did this to demonstrate his justice&rdquo;).</p>",
    "20": "<p>A master who beats a slave to death shall be punished &mdash; the slave has rights before YHWH&apos;s law. The protection of the slave from lethal violence is a fundamental limitation on the master&apos;s authority. Christ&apos;s own incarnation as a slave (Phil 2:7: <em>morphen doulou</em>, &ldquo;the form of a servant/slave&rdquo;) dignifies the slave&apos;s legal status: the Son of God took the form of the most protected-by-law person in the Book of the Covenant.</p>",
    "21": "<p>If the slave survives a day or two, no punishment &mdash; the slave is the master&apos;s property. The provision shows the law working within the ANE institution of slavery while limiting its abuses. The direction of the law is consistently toward protecting life, even of the legally owned. Christ&apos;s death as a slave (Phil 2:8: &ldquo;becoming obedient to death &mdash; even death on a cross&rdquo;) is the ultimate inversion: the master of all becomes the slave who is legally the master&apos;s property.</p>",
    "22": "<p>Fighting men injure a pregnant woman causing premature birth &mdash; if no serious injury, a fine is paid. The law protects the unborn through the principle of compensation for harm to the mother. The protection of life at every stage &mdash; even prenatal &mdash; reflects the image-of-God principle underlying the Decalogue. Christ himself was vulnerable as an unborn child (Luke 1:31-35; Matt 2:13-15), and his life was sought even before birth.</p>",
    "23": "<p>&ldquo;But if there is serious injury, you are to take life for life.&rdquo; The lex talionis principle applied to the most severe outcome. Christ&apos;s atonement operates on the same principle taken to its ultimate conclusion: &ldquo;life for life&rdquo; &mdash; his life for the life of his people. The proportional justice of the law finds its ultimate fulfillment in the cross, where the full weight of the law&apos;s demands is paid in full by the one whose life alone has infinite value.</p>",
    "24": "<p>&ldquo;Eye for eye, tooth for tooth, hand for hand, foot for foot.&rdquo; The lex talionis &mdash; proportional retaliation. Jesus explicitly overturns this as the governing principle of interpersonal ethics in Matt 5:38-42: &ldquo;You have heard it said, &lsquo;An eye for an eye&rsquo;... but I say to you, do not resist the one who is evil.&rdquo; He transcends the lex talionis with non-retaliation and love of enemies. He himself received punishment disproportionate to his conduct so that we might receive mercy disproportionate to ours (2 Cor 5:21).</p>",
    "25": "<p>Burn for burn, wound for wound, bruise for bruise &mdash; the lex talionis applied to lesser injuries. Christ&apos;s body bore every category listed here: &ldquo;by his wounds we are healed&rdquo; (Isa 53:5; 1 Pet 2:24). His bruises (Isa 53:5: <em>daka</em>, crushed) fulfill the lex talionis at the cosmic level &mdash; the one who bore no guilt received every penalty the law prescribes, so that those who bear every guilt might receive every freedom the new covenant provides.</p>",
    "26": "<p>If a master destroys a slave&apos;s eye, the slave goes free for the loss of the eye. The slave&apos;s liberation as compensation for bodily harm acknowledges the slave as a person with inalienable physical dignity &mdash; the body of the slave has legal standing before YHWH. Christ sets every enslaved person free &mdash; not through bodily harm to himself serving as compensation (though he does bear bodily harm, Isa 50:6; 53:3-5) but through his death purchasing freedom for the enslaved (Col 1:13-14).</p>",
    "27": "<p>A knocked-out tooth earns the slave freedom. The smallest injury to the enslaved person&apos;s body triggers liberation. The principle is graduated mercy: the more the powerful damage the vulnerable, the greater the compensation owed. Christ&apos;s liberation of the damaged and broken &mdash; &ldquo;he has sent me to bind up the brokenhearted, to proclaim liberty to the captives&rdquo; (Isa 61:1; Luke 4:18) &mdash; takes the principle to its maximum: all the broken, all the captive, all who are damaged by sin go free through him.</p>",
    "28": "<p>A goring bull that kills a person must be stoned &mdash; the bull&apos;s meat not eaten. The principle: death caused by a dangerous animal is a judicial matter, not merely an accident. The extension of legal categories to animal behavior reflects the thoroughness of the covenant&apos;s reach into all of creation&apos;s order. Christ&apos;s domain extends over all things: he holds all things together (Col 1:17) and will bring all things under his feet (1 Cor 15:27; Eph 1:22).</p>",
    "29": "<p>If the bull was known to be dangerous and the owner was warned but did not pen it in, the owner is liable for execution (though he may pay a ransom). The owner&apos;s culpable negligence transfers the moral liability for the animal&apos;s violence to him. Responsible stewardship of the dangerous is a principle of the covenant law: those entrusted with power bear responsibility for its effects. Christ as the one who will judge the living and the dead (Acts 10:42; 2 Tim 4:1) holds every steward accountable.</p>",
    "30": "<p>The ransom (<em>kofer</em>) that saves the owner&apos;s life &mdash; he may pay whatever is demanded as a ransom. The <em>kofer</em> (ransom, atonement) that substitutes for a life &mdash; the same root as <em>kapporet</em> (atonement cover) and <em>kipper</em> (atone). The ransom-principle in civil law is the type of the substitutionary atonement Christ provides: &ldquo;The Son of Man came to give his life as a ransom (<em>lytron</em>) for many&rdquo; (Matt 20:28; Mark 10:45). His life is the ultimate <em>kofer</em>.</p>",
    "31": "<p>The same law applies if a bull gores a son or a daughter. Children are not second-class victims under the law; the same ransom-provision applies to them as to adults. Christ&apos;s redemption is comprehensive: &ldquo;Let the little children come to me&rdquo; (Mark 10:14) &mdash; the youngest and most vulnerable are equally included in the scope of his saving work (Matt 18:2-5; 19:14).</p>",
    "32": "<p>If the bull gores a male or female slave, the owner pays thirty shekels of silver to the slave&apos;s master. Thirty shekels &mdash; the price of a slave. Zechariah 11:12-13 applies thirty pieces of silver to the rejected shepherd; Matt 27:3-10 applies Zech 11:12-13 to the thirty pieces of silver paid for Jesus&apos;s betrayal. Christ was valued at the price of a slave &mdash; the ultimate inversion: the owner of all creation was sold for the price of the least valuable person in the ancient legal system.</p>",
    "33": "<p>The uncovered pit law &mdash; if someone digs or uncovers a pit and an animal falls in, they must compensate the owner. Responsibility for creating hazards &mdash; even inadvertent hazards &mdash; falls on the one who created them. The principle governs responsible action: known dangers must be guarded. Christ&apos;s warnings (Matt 5:29-30; 18:6-9; Luke 17:1-2) about causing others to stumble reflect the same principle: those who create spiritual hazards bear liability before the ultimate Judge.</p>",
    "34": "<p>The pit-opener compensates the owner and takes the dead animal. The compensation principle: those who cause harm through negligence owe restitution to those harmed. Christ&apos;s redemption includes the restitution-principle: he restores what sin has destroyed, giving back more than was lost &mdash; &ldquo;I will restore to you the years the locusts have eaten&rdquo; (Joel 2:25; cf. Rom 5:20: &ldquo;where sin abounded, grace abounded all the more&rdquo;).</p>",
    "35": "<p>If one bull injures another and it dies, the owners split both the live animal and the proceeds from the dead one. The shared-loss principle distributes harm between parties when neither is fully negligent. The communal sharing of loss reflects the body-of-Christ principle: &ldquo;if one part suffers, every part suffers with it&rdquo; (1 Cor 12:26). Christ enters into human suffering as the supreme instance: he who caused no harm bears all the harm so that those who caused all the harm bear none of the penalty.</p>",
    "36": "<p>If the bull was known to be a gorer and the owner failed to pen it, he must provide full replacement, not just partial compensation. The full-restitution principle underlies the atonement: Christ provides not a partial satisfaction but a complete replacement &mdash; not merely reducing the debt of sin but extinguishing it entirely (Heb 10:14: &ldquo;by one sacrifice he has made perfect forever those who are being made holy&rdquo;).</p>"
  }
}

def main():
    existing = load_comm('mkt-christ', 'exodus')
    merge_comm(existing, EXODUS_CHRIST)
    save_comm('mkt-christ', 'exodus', existing)
    for ch in ['19', '20', '21']:
        vv = existing.get(ch, {})
        print(f'  ch{ch}: {len(vv)} verse(s) with christ commentary')

if __name__ == '__main__':
    main()
